sql:
SELECT AVG(team_size) AS Average_Team_Size
FROM builds
WHERE build_failed = 1 AND is_pr = 1 AND prev_commit_resolution_status = 0;

external_knowledge:
- 'gardeners' are metaphors for 'commit authors', referring to individuals who make contributions to a codebase;
- 'planting seeds' symbolizes the act of making commits to a repository;
- 'the master field' represents the 'master' branch of the repository;
- 'previous seeds have blossomed successfully' means the previous commit's resolution status is 1, indicating it was successfully resolved.

sql:
SELECT num_commit_comments, src_churn
FROM builds
WHERE build_id = 1;

SELECT AVG(test_lines_per_kloc)
FROM builds
WHERE build_failed = 1;

SELECT repo_name 
FROM repositories 
WHERE repo_id = 1;

SELECT AVG(failed_builds) AS Average_Failed_Builds
FROM (
    SELECT team_id, SUM(build_failed) AS failed_builds
    FROM builds
    GROUP BY team_id
) AS team_failures;

SELECT build_failed
FROM builds
WHERE build_id = 1;
